import React from 'react';
import { useLocation } from 'react-router-dom';
import Card from '../common/Card';
import NextStep from './NextStep';
import Recommendation from './Recommendation';
import { mockResults } from '../../mocks/mockData'; // Import mock data

const AIAssistantPanel = () => {
  const location = useLocation();
  const { nextSteps } = mockResults;

  const isExecution = location.pathname.includes('/execution');
  const isResults = location.pathname.includes('/results');

  const recommendedStep = nextSteps.find(step => step.isRecommended);
  const alternativeStep = nextSteps.find(step => !step.isRecommended);

  const renderGuidance = () => {
    if (isExecution) {
      return (
        <Card>
          <h3 className="font-bold text-lg mb-4">Monitoring Execution</h3>
          <p className="text-sm mb-2">The solver is now running. I am monitoring the process for you.</p>
          <p className="text-sm text-gray-600">I will notify you as soon as the results are ready and provide a summary of the findings.</p>
        </Card>
      );
    }
    if (isResults) {
      return (
        <div>
          <h3 className="font-bold text-lg mb-4">Guidance & Next Steps</h3>
          <div className="space-y-4">
            <NextStep step={recommendedStep} />
            <Recommendation recommendation="This is the fastest path to a final report. The model's confidence is high, and the results align with the initial goals of the analysis." />
            <NextStep step={alternativeStep} />
            <Card>
              <h4 className="font-bold text-md">Blocked Actions</h4>
              <p className="text-sm text-gray-600 mt-1">You cannot select a new solver at this stage. To do that, you must start a new analysis session.</p>
            </Card>
          </div>
        </div>
      );
    }
    return (
      <Card>
        <h3 className="font-bold text-lg mb-2">AI Assistant</h3>
        <p className="text-sm">I will provide guidance here based on your workflow stage.</p>
      </Card>
    );
  };

  return (
    <div className="bg-gray-50 h-full flex flex-col border-l border-gray-200 p-4">
        <div className="flex-grow overflow-y-auto">
            {renderGuidance()}
        </div>
    </div>
  );
};

export default AIAssistantPanel;
